import{_ as t,c as d,o as e,a as r}from"./app.87b1f767.js";const u=JSON.parse('{"title":"MySQL 数据类型","description":"","frontmatter":{},"headers":[{"level":2,"title":"数值类型","slug":"数值类型","link":"#数值类型","children":[]},{"level":2,"title":"字符串类型","slug":"字符串类型","link":"#字符串类型","children":[]},{"level":2,"title":"日期类型","slug":"日期类型","link":"#日期类型","children":[]}],"relativePath":"mysql/datatype.md"}'),a={name:"mysql/datatype.md"},l=r('<h1 id="mysql-数据类型" tabindex="-1">MySQL 数据类型 <a class="header-anchor" href="#mysql-数据类型" aria-hidden="true">#</a></h1><p>指的是数据表中的列中支持存放的数据的类型</p><h2 id="数值类型" tabindex="-1">数值类型 <a class="header-anchor" href="#数值类型" aria-hidden="true">#</a></h2><ul><li>在 MySQL 数据库中有多种数据类型可以存放数值，不同类型存放的数值的范围或者形式不同</li></ul><table><thead><tr><th>类型</th><th>内存空间大小</th><th>范围</th><th>说明</th></tr></thead><tbody><tr><td>Tinyint</td><td>1byte</td><td>有符合：-128 ~ 127<br>无符号：0 ~ 255</td><td>特小型整数（年龄）</td></tr><tr><td>Smaillint</td><td>2byte</td><td>有符合：-32768 ~ 32767<br>无符号：0 ~ 65535</td><td>小型整数</td></tr><tr><td>Mediumint</td><td>3byte</td><td>有符合：-2^31 ~ 2^31 - 1<br>无符号：0 ~ 2^32 - 1</td><td>中型整数</td></tr><tr><td>Int/integer</td><td>4byte</td><td></td><td>整数</td></tr><tr><td>Bigint</td><td>8byte</td><td></td><td>大型整数</td></tr><tr><td>Float</td><td>4byte</td><td></td><td>单精度</td></tr><tr><td>Double</td><td>8byte</td><td></td><td>双精度</td></tr><tr><td>Decimal</td><td>第一个参数 + 2</td><td></td><td>decimal(10,2) 表示数值一共有10位，小数位有两位</td></tr></tbody></table><h2 id="字符串类型" tabindex="-1">字符串类型 <a class="header-anchor" href="#字符串类型" aria-hidden="true">#</a></h2><ul><li>存储字符序列的类型</li></ul><table><thead><tr><th>类型</th><th>字符序列的长度范围</th><th>说明</th></tr></thead><tbody><tr><td><code>char</code></td><td>0 ~ 255</td><td>定长字符串，最多可以存储 255 个字符，当我们指定数据字段char<br>此列中的数据最长为 n 个字符，如果添加的数据少于 n，则自补&quot;\\u0000&quot;至 n 长度</td></tr><tr><td><code>varchar</code></td><td>0 ~ 65536</td><td>可变长度字符串，此类型的列最大长度为 65535</td></tr><tr><td>tinyblob</td><td>0 ~ 255</td><td>存储二进制字符串</td></tr><tr><td>blob</td><td>0 ~ 65536</td><td>存储二进制字符串</td></tr><tr><td>mediumblob</td><td>0 ~ 1677215</td><td>存储二进制字符串</td></tr><tr><td>longblob</td><td>0 ~ 4294967295</td><td>存储二进制字符串</td></tr><tr><td>tinytext</td><td>0 ~ 255</td><td>文本数据（字符串）</td></tr><tr><td>text</td><td>0 ~ 65535</td><td>文本数据（字符串）</td></tr><tr><td>mediumtext</td><td>0 ~ 1677215</td><td>文本数据（字符串）</td></tr><tr><td><code>longtext</code></td><td>0 ~ 4294967295</td><td>文本数据（字符串）</td></tr></tbody></table><h2 id="日期类型" tabindex="-1">日期类型 <a class="header-anchor" href="#日期类型" aria-hidden="true">#</a></h2><ul><li>在 MySQL 数据库中，我们可以使用字符串来存储时间，但是如果我们需要基于时间字段进行查询操作（查询在某个时间段内的数据）就不便于查询实现</li></ul><table><thead><tr><th>类型</th><th>格式</th><th>说明</th></tr></thead><tbody><tr><td><code>data</code></td><td>2021-09-15</td><td>日期，只存储年月日</td></tr><tr><td>time</td><td>11:12:13</td><td>日期，只存储时分秒</td></tr><tr><td>year</td><td>2021</td><td>日期，只存储年份</td></tr><tr><td><code>datetime</code></td><td>2021-09-15 11:12:13</td><td>日期，存储年月日+时分秒</td></tr><tr><td>timestamp</td><td>20210915 111213</td><td>日期，存储年月日+时分秒（时间戳）</td></tr></tbody></table>',11),h=[l];function i(o,n,c,s,b,y){return e(),d("div",null,h)}const m=t(a,[["render",i]]);export{u as __pageData,m as default};
